// avio_http_serve_files.c - خادم HTTP صغير يقدّم ملفات عبر AVIO
#include <libavformat/avformat.h>
#include <libavformat/avio.h>
#include <libavutil/opt.h>

int main(int argc, char **argv) {
    const char *root = argv[1] ? argv[1] : ".";
    const char *port = argv[2] ? argv[2] : "8080";

    AVIODirContext *dir = NULL;
    if (avio_open_dir(&dir, root, NULL) < 0) {
        fprintf(stderr, "فشل فتح المجلد: %s\n", root);
        return 1;
    }

    // إنشاء AVIOContext مخصص لقراءة الطلبات
    uint8_t *buf = av_malloc(4096);
    AVIOContext *server = avio_alloc_context(
        NULL, 4096, 0,
        NULL,  // opaque
        NULL, 0, NULL,  // read_packet
        NULL,  // write_packet
        NULL   // seek
    );

    // هنا تُضيف منطق قراءة HTTP الفعلية
    // avio_accept(server, NULL) تنتظر اتصال عميل
    // ثم تقرأ الطلب وتُرجع الملف المطلوب

    avio_close_dir(&dir);
    av_freep(&buf);
    avio_context_free(&server);
    return 0;
}

